#include <bits/stdc++.h>
using namespace std;
int a[105],n,m,dp[105][105],ans=0;
const int N=1e6+7;
int main()
{
	cin>>n>>m;
	for(int i=1;i<=n;i++) cin>>a[i];
	for(int i=0;i<=a[1];i++) dp[1][i]=1;
	for(int i=2;i<n;i++)
	{
		for(int j=0;j<=m;j++)
		{
			for(int k=max(0,j-a[i]);k<=j;k++) dp[i][j]+=dp[i-1][k],dp[i][j]%=N;
		}
	}
	for(int i=max(0,m-a[n]);i<=m;i++) dp[n][m]+=dp[n-1][i],dp[n][m]%=N;
	cout<<dp[n][m];
	return 0;
}
